def solve_mod_stamp(N, M, K, board, stamps):
    MOD = 998244353
    placements = []
    for _ in range(K):
        best_inc = 0
        best_pos = None
        for m in range(M):
            for i in range(N - 2):
                for j in range(N - 2):
                    inc = 0
                    for r in range(3):
                        for c in range(3):
                            inc += stamps[m][r][c]
                    if inc > best_inc:
                        best_inc = inc
                        best_pos = (m, i, j)
        if best_pos:
            m, i, j = best_pos
            placements.append((m, i, j))
            for r in range(3):
                for c in range(3):
                    board[i+r][j+c] = (board[i+r][j+c] + stamps[m][r][c]) % MOD
        else:
            break
    return len(placements), placements

